1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const LOYALTY_THRESHOLD = 2;
21	const LOYALTY_RATE = 0.2;
22	
23	interface QuoteStep {
24	  op: "quote";
25	  items: Item[];
26	}
27	
28	interface Damage {
29	  itemType: string;
30	  amount: number;
31	}
32	
33	interface ClaimStep {
34	  op: "claim";
35	  policy: number;
36	  incident: { cause: string; damages: Damage[] };
37	}
38	
39	type Step = QuoteStep | ClaimStep;
40	
41	interface Customer {
42	  yearsWithMHPCO: number;
43	}
44	
45	interface Scenario {
46	  customer: Customer;
47	  steps: Step[];
48	}
49	
50	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
51	const COMPONENT_BASE = 25;
52	const BLOCK_SIZE = 3;
53	const BLOCK_BASE = 60;
54	
55	const componentBase = (count: number): number =>
56	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
57	
58	const lookupByType = (
59	  type: string,
60	  componentValue: number,
61	  mainItemValues: Record<string, number>,
62	): number =>
63	  COMPONENT_TYPES.has(type) ? componentValue : (mainItemValues[type] ?? 0);
64	
65	const unitBase = (type: string): number =>
66	  lookupByType(type, COMPONENT_BASE, BASE_PREMIUMS);
67	
68	const baseForType = (type: string, count: number): number =>
69	  COMPONENT_TYPES.has(type)
70	    ? componentBase(count)
71	    : unitBase(type) * count;
72	
73	const countBy = <T>(values: T[], key: (value: T) => string): Map<string, number> =>
74	  values.reduce((counts, value) => {
75	    const group = key(value);
76	    return counts.set(group, (counts.get(group) ?? 0) + 1);
77	  }, new Map<string, number>());
78	
79	const countByType = (items: Item[]): Map<string, number> =>
80	  countBy(items, (item) => item.type);
81	
82	const baseForItems = (items: Item[]): number =>
83	  [...countByType(items)].reduce(
84	    (total, [type, count]) => total + baseForType(type, count),
85	    0,
86	  );
87	
88	const enchantmentLevel = (item: Item | undefined): number =>
89	  item?.enchantment ?? 0;
90	
91	const isHighlyEnchanted = (item: Item): boolean =>
92	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
93	
94	const surchargeRate = (item: Item): number =>
95	  (item.cursed ? CURSE_RATE : 0) +
96	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
97	
98	const itemSurcharges = (item: Item): number =>
99	  unitBase(item.type) * surchargeRate(item);
100	
101	const surchargesForItems = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
103	
104	const firstInsuranceSurcharge = (policyBase: number): number =>
105	  policyBase * FIRST_INSURANCE_RATE;
106	
107	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
108	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
109	
110	const isKnownType = (type: string): boolean =>
111	  COMPONENT_TYPES.has(type) || type in BASE_PREMIUMS;
112	
113	const validateKnownTypes = (items: Item[]): void => {
114	  for (const item of items) {
115	    if (!isKnownType(item.type)) {
116	      throw new Error(`Unknown item type: ${item.type}`);
117	    }
118	  }
119	};
120	
121	const priceQuote = (items: Item[], customer: Customer): { premium: number } => {
122	  validateKnownTypes(items);
123	  const policyBase = baseForItems(items);
124	  const surcharges = surchargesForItems(items);
125	  const premium = Math.ceil(
126	    policyBase +
127	      surcharges +
128	      firstInsuranceSurcharge(policyBase) -
129	      loyaltyDiscount(policyBase, customer) +
130	      PROCESSING_FEE,
131	  );
132	  return { premium };
133	};
134	
135	const DEDUCTIBLE = 100;
136	const CAP_MULTIPLIER = 2;
137	const HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD = 8;
138	const REIMBURSE_RATE = 0.5;
139	
140	const INSURANCE_VALUES: Record<string, number> = {
141	  sword: 1000,
142	  amulet: 600,
143	  staff: 800,
144	  potion: 400,
145	};
146	const COMPONENT_INSURANCE_VALUE = 250;
147	
148	const insuranceValue = (type: string): number =>
149	  lookupByType(type, COMPONENT_INSURANCE_VALUE, INSURANCE_VALUES);
150	
151	const insuranceSum = (items: Item[]): number =>
152	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
153	
154	const hasReducedReimbursement = (item: Item | undefined): boolean =>
155	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD;
156	
157	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
158	  hasReducedReimbursement(item)
159	    ? damage.amount * REIMBURSE_RATE
160	    : damage.amount;
161	
162	const damagePayout = (damage: Damage, items: Item[]): number => {
163	  const item = items.find((candidate) => candidate.type === damage.itemType);
164	  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
165	};
166	
167	const initialCap = (items: Item[]): number =>
168	  insuranceSum(items) * CAP_MULTIPLIER;
169	
170	const desiredPayout = (damages: Damage[], items: Item[]): number =>
171	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
172	
173	const validateDamageAmounts = (damages: Damage[]): void => {
174	  for (const damage of damages) {
175	    if (damage.amount < 0) {
176	      throw new Error(`Claim rejected: negative damage amount ${damage.amount}`);
177	    }
178	  }
179	};
180	
181	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
182	  const insuredCounts = countByType(items);
183	  const damageCounts = countBy(damages, (damage) => damage.itemType);
184	  for (const [itemType, damaged] of damageCounts) {
185	    if (damaged > (insuredCounts.get(itemType) ?? 0)) {
186	      throw new Error(
187	        `Claim rejected: more "${itemType}" damages than insured items`,
188	      );
189	    }
190	  }
191	};
192	
193	const validateClaim = (damages: Damage[], items: Item[]): void => {
194	  validateDamageAmounts(damages);
195	  validateDamageCounts(damages, items);
196	};
197	
198	const processClaim = (
199	  step: ClaimStep,
200	  steps: Step[],
201	  remainingCapByPolicy: Map<number, number>,
202	): { payout: number; remainingCap: number } => {
203	  const policyStep = steps[step.policy] as QuoteStep;
204	  validateClaim(step.incident.damages, policyStep.items);
205	  const remaining =
206	    remainingCapByPolicy.get(step.policy) ?? initialCap(policyStep.items);
207	  const desired = desiredPayout(step.incident.damages, policyStep.items);
208	  const payout = Math.floor(Math.min(desired, remaining));
209	  const remainingCap = remaining - payout;
210	  remainingCapByPolicy.set(step.policy, remainingCap);
211	  return { payout, remainingCap };
212	};
213	
214	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
215	  const remainingCapByPolicy = new Map<number, number>();
216	  const results = scenario.steps.map((step) =>
217	    step.op === "quote"
218	      ? priceQuote(step.items, scenario.customer)
219	      : processClaim(step, scenario.steps, remainingCapByPolicy),
220	  );
221	  return { results };
222	};
